let ImageSys, InPutButton, SendButton, FileInput;
let InputRotateButton, OutputRotateButton;
let modeButtons, tips;

let currentMode = 'AP';

let inputRotate = 0;   // 输入旋转（影响处理）
let outputRotate = 0;  // 输出旋转（仅显示）

let processedBase64 = "";
let fileFlag = 0;

// ================= 模式相关 =================
function updateModeByValue(targetMode) {
    const validModes = ['AP', 'STA'];
    if (!validModes.includes(targetMode)) targetMode = 'AP';

    const activeButton = document.querySelector(`a[data-mode="${targetMode}"]`);
    if (activeButton) {
        modeButtons.forEach(btn => btn.classList.remove('active'));
        activeButton.classList.add('active');
        currentMode = targetMode;
        updateTips();
    }
}

function updateTips() {
    tips.forEach(tip => tip.classList.remove('d-none'));
    if (currentMode === "AP") {
        document.getElementById('tips-STA')?.classList.add('d-none');
    } else {
        document.getElementById('tips-AP')?.classList.add('d-none');
    }
}

// ================= 初始化 =================
function Even_init() {
    InPutButton = document.getElementById("Input_Button");
    SendButton = document.getElementById("Send_Button");
    FileInput = document.getElementById("File_Input");
    ImageSys = document.getElementById("Image_Input");

    InputRotateButton = document.getElementById("InputRotate_Button");
    OutputRotateButton = document.getElementById("OutputRotate_Button");

    InputRotateButton.textContent = `Input Rotate: ${inputRotate}°`;
    OutputRotateButton.textContent = `Output Rotate: ${outputRotate}°`;

    InPutButton.addEventListener("click", () => FileInput.click());
    FileInput.addEventListener("change", FileInput_Even);
    SendButton.addEventListener("click", SendButton_Even);

    InputRotateButton.addEventListener("click", InputRotateButton_Even);
    OutputRotateButton.addEventListener("click", OutputRotateButton_Even);
}

// ================= 核心：图像处理 =================
function processImage() {
    if (!originalImageURL) return;

    const img = new Image();
    // if (!ImageSys.src) return;

    // const img = new Image();
    img.onload = function () {

        // ===== 1. 输入旋转 =====
        let w = img.naturalWidth, h = img.naturalHeight;

        let canvasRotate = document.createElement('canvas');
        let ctxRotate = canvasRotate.getContext('2d');

        if (inputRotate % 180 === 0) {
            canvasRotate.width = w;
            canvasRotate.height = h;
        } else {
            canvasRotate.width = h;
            canvasRotate.height = w;
        }

        ctxRotate.translate(canvasRotate.width / 2, canvasRotate.height / 2);
        ctxRotate.rotate(inputRotate * Math.PI / 180);
        ctxRotate.drawImage(img, -w / 2, -h / 2);

        // ===== 2. 缩放 =====
        let targetW, targetH;
        if (canvasRotate.width > canvasRotate.height) {
            targetW = 1600;
            targetH = 1200;
        } else {
            targetW = 1200;
            targetH = 1600;
        }

        const canvas = document.createElement('canvas');
        canvas.width = targetW;
        canvas.height = targetH;
        const ctx = canvas.getContext('2d');

        ctx.drawImage(canvasRotate, 0, 0, targetW, targetH);

        // ===== 3. 量化 =====
        const imageData = ctx.getImageData(0, 0, targetW, targetH);
        const data = imageData.data;

        const palette = [
            [0, 0, 0],
            [255, 255, 255],
            [255, 255, 0],
            [255, 0, 0],
            null,
            [0, 0, 255],
            [0, 255, 0]
        ];

        function findNearestColorIndex(r, g, b) {
            let minDist = Infinity, idx = 0;
            for (let i = 0; i < palette.length; i++) {
                if (!palette[i]) continue;
                const [pr, pg, pb] = palette[i];
                const dist = (r - pr) ** 2 + (g - pg) ** 2 + (b - pb) ** 2;
                if (dist < minDist) {
                    minDist = dist;
                    idx = i;
                }
            }
            return idx;
        }

        for (let y = 0; y < targetH; y++) {
            for (let x = 0; x < targetW; x++) {

                const i = (y * targetW + x) * 4;

                const oldR = data[i];
                const oldG = data[i + 1];
                const oldB = data[i + 2];

                const idx = findNearestColorIndex(oldR, oldG, oldB);
                const [newR, newG, newB] = palette[idx];

                data[i] = newR;
                data[i + 1] = newG;
                data[i + 2] = newB;

                const errR = oldR - newR;
                const errG = oldG - newG;
                const errB = oldB - newB;

                // 右
                if (x + 1 < targetW) {
                    let j = i + 4;
                    data[j] += errR * 7 / 16;
                    data[j + 1] += errG * 7 / 16;
                    data[j + 2] += errB * 7 / 16;
                }

                // 左下
                if (x > 0 && y + 1 < targetH) {
                    let j = i + (targetW - 1) * 4;
                    data[j] += errR * 3 / 16;
                    data[j + 1] += errG * 3 / 16;
                    data[j + 2] += errB * 3 / 16;
                }

                // 下
                if (y + 1 < targetH) {
                    let j = i + targetW * 4;
                    data[j] += errR * 5 / 16;
                    data[j + 1] += errG * 5 / 16;
                    data[j + 2] += errB * 5 / 16;
                }

                // 右下
                if (x + 1 < targetW && y + 1 < targetH) {
                    let j = i + (targetW + 1) * 4;
                    data[j] += errR * 1 / 16;
                    data[j + 1] += errG * 1 / 16;
                    data[j + 2] += errB * 1 / 16;
                }
            }
        }

        ctx.putImageData(imageData, 0, 0);

        processedBase64 = canvas.toDataURL();

        // ===== 4. 输出渲染 =====
        renderOutput();
    };

    // img.src = ImageSys.src;
    img.src = originalImageURL;   // 🔥 用原图
}

// ================= 输出旋转显示 =================
function renderOutput() {
    if (!processedBase64) return;

    const img = new Image();
    const processedImg = document.getElementById('Image_Processed');

    img.onload = function () {
        let w = img.naturalWidth, h = img.naturalHeight;

        let canvas = document.createElement('canvas');
        let ctx = canvas.getContext('2d');

        if (outputRotate % 180 === 0) {
            canvas.width = w;
            canvas.height = h;
        } else {
            canvas.width = h;
            canvas.height = w;
        }

        ctx.translate(canvas.width / 2, canvas.height / 2);
        ctx.rotate(outputRotate * Math.PI / 180);
        ctx.drawImage(img, -w / 2, -h / 2);

        processedImg.src = canvas.toDataURL();
    };

    img.src = processedBase64;
}

// ================= 事件 =================
function FileInput_Even(e) {
    const file = e.target.files[0];
    if (!file || !file.type.startsWith("image/")) {
        alert("Please select an image file");
        return;
    }

    originalImageURL = URL.createObjectURL(file);
    ImageSys.src = originalImageURL;

    fileFlag = 1;
    e.target.value = '';

    processImage();   // 🔥 直接处理
}

// 输入旋转（重算）
function InputRotateButton_Even() {
    if (!fileFlag) return;

    inputRotate = (inputRotate + 90) % 360;

    InputRotateButton.textContent = `Input Rotate: ${inputRotate}°`;

    // ✅ UI显示旋转（关键！）
    ImageSys.style.transform = `rotate(${inputRotate}deg)`;

    // ✅ 重新处理（数据层）
    processImage();
}

// 输出旋转（仅显示）
function OutputRotateButton_Even() {
    if (!processedBase64) return;

    outputRotate = (outputRotate + 90) % 360;
    OutputRotateButton.textContent = `Output Rotate: ${outputRotate}°`;

    renderOutput();
}

// ================= 发送 =================
function SendButton_Even() {
    if (!processedBase64) {
        alert("No processed image");
        return;
    }

    let modeByte = currentMode === "STA" ? 0x01 : 0x00;

    const img = new Image();
    img.onload = function () {

        let w = img.naturalWidth, h = img.naturalHeight;

        // ===== ① 应用“输出旋转”（关键！）=====
        let canvas = document.createElement('canvas');
        let ctx = canvas.getContext('2d');

        if (outputRotate % 180 === 0) {
            canvas.width = w;
            canvas.height = h;
        } else {
            canvas.width = h;
            canvas.height = w;
        }

        ctx.translate(canvas.width / 2, canvas.height / 2);
        ctx.rotate(outputRotate * Math.PI / 180);
        ctx.drawImage(img, -w / 2, -h / 2);

        // ===== ② 获取最终图像数据 =====
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const data = imageData.data;

        function colorIndex(r, g, b) {
            if (r === 0 && g === 0 && b === 0) return 0;
            if (r === 255 && g === 255 && b === 255) return 1;
            if (r === 255 && g === 255 && b === 0) return 2;
            if (r === 255 && g === 0 && b === 0) return 3;
            if (r === 0 && g === 0 && b === 255) return 5;
            if (r === 0 && g === 255 && b === 0) return 6;
            return 1;
        }

        const pixelCount = canvas.width * canvas.height;
        const packedLen = Math.ceil(pixelCount / 2);
        const packed = new Uint8Array(1 + packedLen);

        // ===== flag 计算 =====
        let flag = 0x00;

        if (canvas.width === 1600 && canvas.height === 1200) {
            flag = 0x10;
        }

        // ===== 协议头 =====
        packed[0] = (flag | modeByte) & 0xff;
        // packed[0] = modeByte;

        for (let i = 0, j = 1; i < pixelCount; i += 2, j++) {
            const idx1 = i * 4;
            const idx2 = (i + 1) * 4;

            const v1 = colorIndex(data[idx1], data[idx1 + 1], data[idx1 + 2]) & 0x0F;
            let v2 = 0x0F;

            if (i + 1 < pixelCount) {
                v2 = colorIndex(data[idx2], data[idx2 + 1], data[idx2 + 2]) & 0x0F;
            }

            packed[j] = (v1 << 4) | v2;
        }

        // ===== ③ 发送 =====
        fetch("/dataUP", {
            method: "POST",
            headers: { "Content-Type": "application/octet-stream" },
            body: packed
        })
        .then(res => res.text())
        .then(msg => alert("Upload successful: " + msg))
        .catch(() => alert("Upload failed"));
    };

    img.src = processedBase64;
}

// ================= 启动 =================
document.addEventListener('DOMContentLoaded', function () {
    modeButtons = document.querySelectorAll('a[data-mode]');
    tips = document.querySelectorAll('#tips > div');

    modeButtons.forEach(button => {
        button.addEventListener('click', function(e) {
            e.preventDefault();
            updateModeByValue(this.dataset.mode);
        });
    });

    Even_init();
});